(function(){document.readyState==="loading"?document.addEventListener("DOMContentLoaded",e):e();function e(){const e=document.querySelectorAll(".menu-item-has-children");e.forEach(e=>{const t=e.querySelector("a");t.addEventListener("click",t=>{t.preventDefault(),e.classList.toggle("active")})});const t=localStorage.getItem("navFoldState");t==="folded"&&document.body.classList.add("nav-folded")}})()